import warnings
from functools import wraps

def deprecated(*, replacement: str, since: str):
    """Emits DeprecationWarning once per call site."""
    def decorator(fn):
        warned_sites: set[str] = set()
        @wraps(fn)
        def wrapper(*args, **kwargs):
            import traceback
            site = traceback.extract_stack()[-2].filename
            if site not in warned_sites:
                warnings.warn(
                    f"{fn.__qualname__} is deprecated since {since}. "
                    f"Use {replacement} instead.",
                    DeprecationWarning,
                    stacklevel=2,
                )
                warned_sites.add(site)
            return fn(*args, **kwargs)
        return wrapper
    return decorator

