import pathlib, toml
from packaging.version import Version
from packaging.specifiers import SpecifierSet

LIBRARIES = ["internal-llm-sdk", "genai-auth", "genai-telemetry"]

# Populated from the platform version-lifecycle YAML maintained in the IDP
SUPPORT_WINDOWS = {
    "internal-llm-sdk": {
        "active":   SpecifierSet("~=2.0"),
        "security": SpecifierSet("~=1.0"),
        "eol":      SpecifierSet("<1.0"),
    },
    # ... (similar for genai-auth, genai-telemetry)
}

def classify_pin(lib: str, pin_spec: str) -> str:
    """Return 'ok' | 'warning' | 'block'."""
    windows = SUPPORT_WINDOWS.get(lib, {})
    spec = SpecifierSet(pin_spec.replace("~=", "~="))
    # Sample a few versions to determine which window the pin falls in
    test_versions = ["0.9.0","1.0.0","1.8.0","2.0.0","2.4.0","2.5.0"]
    matched = [v for v in test_versions if Version(v) in spec]
    if not matched:
        return "unknown"
    latest_match = max(matched, key=Version)
    if Version(latest_match) in windows.get("eol", SpecifierSet()):
        return "block"
    if Version(latest_match) in windows.get("security", SpecifierSet()):
        return "warning"
    return "ok"

def scan_service(repo_root: pathlib.Path) -> dict:
    pyproject = repo_root / "pyproject.toml"
    if not pyproject.exists():
        return {"error": "no pyproject.toml"}
    data = toml.loads(pyproject.read_text())
    deps = (data.get("tool", {}).get("poetry", {})
                .get("dependencies", {}))
    return {
        lib: {
            "pin":    deps.get(lib, "NOT PINNED"),
            "status": classify_pin(lib, deps.get(lib, "")) if lib in deps else "missing",
        }
        for lib in LIBRARIES
    }
